sp_instance.widget_parameters:
{
	"html": {
		"value": "<div class="steps-section">
<h2 class="section-title">How It Works</h2>
<div class="title-decoration">&nbsp;</div>
<div class="steps-grid">
<div class="step-item">
<div class="step-number">1</div>
<h3>Select Medicine</h3>
<p>Browse or search for your medicine</p>
</div>
<div class="step-item">
<div class="step-number">2</div>
<h3>Place Order</h3>
<p>Fill the form and get approval</p>
</div>
<div class="step-item">
<div class="step-number">3</div>
<h3>Pickup</h3>
<p>Collect from pharmacy</p>
</div>
</div>
</div>
<style>
.steps-section {
  background: #FFFFFF;
  border-radius: 32px;
  padding: 3rem 2rem;
  margin-bottom: 50px;
  border: 1px solid #E2E8F0;
}
.section-title {
  font-size: 28px;
  font-weight: 700;
  margin: 2rem 0 1rem;
  text-align: center;
  color: #0F172A;
}
.title-decoration {
  width: 70px;
  height: 4px;
  background: #E60000;
  margin: 0.5rem auto 2rem auto;
  border-radius: 4px;
}
.steps-grid {
  display: flex;
  gap: 2rem;
  justify-content: center;
  flex-wrap: wrap;
  margin-top: 2rem;
}
.step-item {
  text-align: center;
  flex: 1;
  min-width: 200px;
}
.step-number {
  background: #E60000;
  color: white;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 28px;
  font-weight: bold;
  margin-bottom: 1rem;
}
.step-item h3 {
  font-size: 20px;
  margin-bottom: 0.5rem;
}
.step-item p {
  color: #64748B;
  font-size: 14px;
}
@media (max-width: 768px) {
  .steps-grid {
    gap: 1rem;
  }
}
</style>",
